// ─────────────────────────────────────────────────────────
// n8n Code Node — Resume Parser (No AI needed)
// Input:  $json.text  (resume ka plain text)
// Output: structured JSON with all resume fields
// ─────────────────────────────────────────────────────────

const text = $input.item.json.text || "";

function extractResumeData(text) {
  const result = {
    name: null,
    email: null,
    phone: null,
    location: null,
    linkedin: null,
    github: null,
    website: null,
    summary: null,
    skills: [],
    languages: [],
    education: [],
    experience: [],
    certifications: [],
    projects: []
  };

  const lines = text.split("\n").map(l => l.trim()).filter(l => l.length > 0);

  // ── 1. EMAIL ──────────────────────────────────────────
  const emailMatch = text.match(/[\w.\-+]+@[\w\-]+\.[a-zA-Z]{2,}/);
  if (emailMatch) result.email = emailMatch[0];

  // ── 2. PHONE ──────────────────────────────────────────
  const phoneMatch = text.match(/(\+?[\d][\d\s\-().]{7,}[\d])/);
  if (phoneMatch) result.phone = phoneMatch[0].trim();

  // ── 3. LINKEDIN / GITHUB / WEBSITE ────────────────────
  const linkedinMatch = text.match(/linkedin\.com\/in\/[\w\-]+/i);
  if (linkedinMatch) result.linkedin = "https://" + linkedinMatch[0];

  const githubMatch = text.match(/github\.com\/[\w\-]+/i);
  if (githubMatch) result.github = "https://" + githubMatch[0];

  const websiteMatch = text.match(/https?:\/\/(?!linkedin|github)[\w.\-\/]+/i);
  if (websiteMatch) result.website = websiteMatch[0];

  // ── 4. NAME (pehli 1-5 lines mein se) ────────────────
  for (let i = 0; i < Math.min(5, lines.length); i++) {
    const line = lines[i];
    const wordCount = line.split(/\s+/).length;
    if (
      !/@|http|linkedin|github|\d{5}/.test(line) &&
      wordCount >= 1 &&
      wordCount <= 5 &&
      /^[A-Z]/.test(line)
    ) {
      result.name = line;
      break;
    }
  }

  // ── 5. SECTION PARSER ─────────────────────────────────
  const SECTION_MAP = {
    summary:        /summary|objective|profile|about\s*me/i,
    skills:         /skills|technical\s*skills|core\s*competencies|technologies/i,
    experience:     /experience|work\s*experience|employment|work\s*history/i,
    education:      /education|academic|qualification/i,
    certifications: /certif|licens|credential/i,
    projects:       /projects?/i,
    languages:      /languages?|spoken/i,
  };

  function getSections(text) {
    const sections = {};
    const sectionKeys = Object.keys(SECTION_MAP);

    // section headings dhundho (line jo sirf heading ho)
    const sectionPositions = [];
    const textLines = text.split("\n");

    textLines.forEach((line, idx) => {
      const clean = line.trim();
      if (!clean) return;
      for (const key of sectionKeys) {
        if (
          SECTION_MAP[key].test(clean) &&
          clean.length < 50 &&           // heading zyada lambi nahi hogi
          !/[.@]/.test(clean)            // email ya sentence nahi
        ) {
          sectionPositions.push({ key, idx });
          break;
        }
      }
    });

    for (let i = 0; i < sectionPositions.length; i++) {
      const { key, idx } = sectionPositions[i];
      const endIdx = i + 1 < sectionPositions.length
        ? sectionPositions[i + 1].idx
        : textLines.length;
      const content = textLines.slice(idx + 1, endIdx).join("\n").trim();
      sections[key] = content;
    }

    return sections;
  }

  const sections = getSections(text);

  // ── 6. SUMMARY ────────────────────────────────────────
  if (sections.summary) {
    result.summary = sections.summary.replace(/\n/g, " ").trim();
  }

  // ── 7. SKILLS ─────────────────────────────────────────
  if (sections.skills) {
    let raw = sections.skills.replace(/[•\-\*▪◦]/g, ",");
    const skills = raw
      .split(/[,\n|\/]/)
      .map(s => s.trim())
      .filter(s => s.length > 1 && s.length < 50);
    result.skills = [...new Set(skills)]; // duplicates hatao
  }

  // ── 8. LANGUAGES ──────────────────────────────────────
  const KNOWN_LANGS = [
    "english","urdu","arabic","french","german",
    "spanish","chinese","hindi","punjabi","turkish",
    "persian","japanese","portuguese","russian","italian"
  ];
  const langSource = (sections.languages || text).toLowerCase();
  result.languages = KNOWN_LANGS
    .filter(l => langSource.includes(l))
    .map(l => l.charAt(0).toUpperCase() + l.slice(1));

  // ── 9. EDUCATION ──────────────────────────────────────
  if (sections.education) {
    const degreeRe = /bachelor|master|b\.?s\.?|m\.?s\.?|phd|b\.?e|m\.?b\.?a|matric|intermediate|fsc|bsc|associate/i;
    const yearRe   = /(19|20)\d{2}/;
    const eduLines = sections.education.split("\n").map(l => l.trim()).filter(Boolean);

    eduLines.forEach((line, i) => {
      if (degreeRe.test(line)) {
        const entry = {
          degree:      line,
          institution: eduLines[i + 1] || null,
          year:        null
        };
        const yearMatch = line.match(yearRe) || (eduLines[i+1] || "").match(yearRe);
        if (yearMatch) entry.year = yearMatch[0];
        result.education.push(entry);
      }
    });
  }

  // ── 10. EXPERIENCE ────────────────────────────────────
  if (sections.experience) {
    const dateRe = /((jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*[\s,]+\d{4}|(\d{4})\s*[-–]\s*(\d{4}|present|current|now))/i;
    const blocks = sections.experience.split(/\n{2,}/);

    blocks.forEach(block => {
      const bLines = block.split("\n").map(l => l.trim()).filter(Boolean);
      if (!bLines.length) return;

      const entry = {
        title:       bLines[0] || null,
        company:     bLines[1] || null,
        duration:    null,
        description: bLines.slice(2).join(" ") || null
      };

      const dateMatch = block.match(dateRe);
      if (dateMatch) entry.duration = dateMatch[0].trim();

      result.experience.push(entry);
    });
  }

  // ── 11. CERTIFICATIONS ────────────────────────────────
  if (sections.certifications) {
    result.certifications = sections.certifications
      .split("\n")
      .map(l => l.trim().replace(/^[\-•*\d.]+\s*/, ""))
      .filter(l => l.length > 3);
  }

  // ── 12. PROJECTS ──────────────────────────────────────
  if (sections.projects) {
    const projBlocks = sections.projects.split(/\n{2,}/);
    projBlocks.forEach(block => {
      const pLines = block.split("\n").map(l => l.trim()).filter(Boolean);
      if (pLines.length) {
        result.projects.push({
          name:        pLines[0],
          description: pLines.slice(1).join(" ") || null
        });
      }
    });
  }

  // ── 13. LOCATION ──────────────────────────────────────
  const locMatch = text.match(/\b([A-Z][a-z]+(?:\s[A-Z][a-z]+)?,\s*[A-Z][a-z]+(?:\s[A-Z][a-z]+)?)\b/);
  if (locMatch) result.location = locMatch[0].trim();

  return result;
}

// ─── Run & Return ────────────────────────────────────────
const extracted = extractResumeData(text);

return {
  json: {
    ...extracted
  }
};

// ─────────────────────────────────────────────────────────
// n8n Code Node — Resume Parser
// Output format: Affinda-style (Name, Email, Phone, Gender,
//   Skills, City, State, Country, WorkHistory, Education, etc.)
// ─────────────────────────────────────────────────────────

const text = $input.item.json.text || "";

function extractResumeData(text) {

  // ── HELPERS ───────────────────────────────────────────
  function firstMatch(pattern, src) {
    const m = (src || text).match(pattern);
    return m ? m[0].trim() : null;
  }

  function getSections(txt) {
    const SECTION_MAP = {
      summary:        /^\s*(summary|objective|profile|about\s*me)\s*:?\s*$/i,
      skills:         /^\s*(skills|technical\s*skills|core\s*competencies|technologies|key\s*skills)\s*:?\s*$/i,
      experience:     /^\s*(experience|work\s*experience|employment|work\s*history|professional\s*experience)\s*:?\s*$/i,
      education:      /^\s*(education|academic|qualification|academic\s*background)\s*:?\s*$/i,
      certifications: /^\s*(certif|licens|credential|courses?)\s*:?\s*$/i,
      projects:       /^\s*(projects?|personal\s*projects?)\s*:?\s*$/i,
      languages:      /^\s*(languages?|spoken)\s*:?\s*$/i,
    };

    const sections = {};
    const lines = txt.split("\n");
    const positions = [];

    lines.forEach((line, idx) => {
      const clean = line.trim();
      if (!clean || clean.length > 60) return;
      for (const [key, re] of Object.entries(SECTION_MAP)) {
        if (re.test(clean) && !/@|\.com/.test(clean)) {
          positions.push({ key, idx });
          break;
        }
      }
    });

    positions.forEach(({ key, idx }, i) => {
      const end = i + 1 < positions.length ? positions[i + 1].idx : lines.length;
      sections[key] = lines.slice(idx + 1, end).join("\n").trim();
    });

    return sections;
  }

  const sections = getSections(text);
  const lines = text.split("\n").map(l => l.trim()).filter(Boolean);

  // ── 1. NAME ───────────────────────────────────────────
  let name = null;
  for (let i = 0; i < Math.min(5, lines.length); i++) {
    const line = lines[i];
    const words = line.split(/\s+/);
    if (
      !/@|http|linkedin|github|\d{4}/.test(line) &&
      words.length >= 2 && words.length <= 5 &&
      /^[A-Z]/.test(line) &&
      words.every(w => /^[A-Za-z'\-\.]+$/.test(w))
    ) {
      name = line;
      break;
    }
  }

  // ── 2. EMAIL ──────────────────────────────────────────
  const email = firstMatch(/[\w.\-+]+@[\w\-]+\.[a-zA-Z]{2,}/);

  // ── 3. PHONE ──────────────────────────────────────────
  const phone = firstMatch(/(\+?[\d][\d\s\-().]{7,}[\d])/);

  // ── 4. LINKEDIN ───────────────────────────────────────
  const linkedinRaw = firstMatch(/linkedin\.com\/in\/[\w\-]+/i);
  const linkedInUrl = linkedinRaw ? "https://" + linkedinRaw : null;

  // ── 5. SKILLS ─────────────────────────────────────────
  let skills = null;
  if (sections.skills) {
    let raw = sections.skills.replace(/[•\-\*▪◦]/g, ",");
    const arr = raw.split(/[,\n|\/]/)
      .map(s => s.trim())
      .filter(s => s.length > 1 && s.length < 60);
    skills = [...new Set(arr)].join(", ");
  }

  // ── 6. LOCATION ───────────────────────────────────────
  // Try "City, State, Country" or "City, Country"
  let city = null, state = null, country = null, fullAddress = null;

  const locationPatterns = [
    // e.g. "Gandhinagar, Gujarat, India"
    /([A-Z][a-z]+(?:\s[A-Z][a-z]+)?),\s*([A-Z][a-z]+(?:\s[A-Z][a-z]+)?),\s*([A-Z][a-z]+)/,
    // e.g. "Gandhinagar, India"
    /([A-Z][a-z]+(?:\s[A-Z][a-z]+)?),\s*([A-Z][a-z]+)/,
  ];

  for (const pat of locationPatterns) {
    const m = text.match(pat);
    if (m) {
      if (m[3]) {
        city = m[1]; state = m[2]; country = m[3];
        fullAddress = `${city}, ${state}, ${country}`;
      } else {
        city = m[1]; country = m[2];
        fullAddress = `${city}, ${country}`;
      }
      break;
    }
  }

  // known countries list se bhi try karo
  const COUNTRIES = ["India","Pakistan","USA","UK","Canada","Australia","Germany","UAE","Saudi Arabia","Qatar"];
  if (!country) {
    for (const c of COUNTRIES) {
      if (text.includes(c)) { country = c; break; }
    }
  }

  // ── 7. WORK HISTORY (single string, comma separated) ──
  let workHistory = null;
  let positionTitle = null;
  let currentOrganization = null;
  let totalExperience = null;

  if (sections.experience) {
    const dateRe = /((jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*[\s\-']*\d{2,4}|\d{4})/gi;
    const blocks = sections.experience.split(/\n{2,}/);
    const workEntries = [];

    blocks.forEach(block => {
      const bLines = block.split("\n").map(l => l.trim()).filter(Boolean);
      if (!bLines.length) return;

      const title    = bLines[0] || "";
      const company  = bLines[1] || "";
      const dates    = block.match(dateRe);
      const duration = dates ? dates.slice(0, 2).join("-") : "";

      if (title) {
        const entry = duration
          ? `${title} at ${company} (${duration})`
          : `${title} at ${company}`;
        workEntries.push(entry.trim());
      }
    });

    workHistory = workEntries.join(", ") || null;

    // First entry = current position
    if (blocks.length > 0) {
      const firstLines = blocks[0].split("\n").map(l => l.trim()).filter(Boolean);
      positionTitle       = firstLines[0] || null;
      currentOrganization = firstLines[1] || null;
    }

    // Total experience: year range detect karo
    const allYears = sections.experience.match(/\b(19|20)\d{2}\b/g);
    if (allYears && allYears.length >= 2) {
      const sorted = allYears.map(Number).sort((a, b) => a - b);
      const diff = new Date().getFullYear() - sorted[0];
      if (diff > 0) totalExperience = `Over ${diff} Years`;
    }
  }

  // ── 8. EDUCATION (single string) ──────────────────────
  let education = null;
  if (sections.education) {
    const degreeRe = /bachelor|master|b\.?s\.?|m\.?s\.?|phd|b\.?e|m\.?b\.?a|matric|intermediate|fsc|bsc|associate|diploma|certificate|mba/i;
    const eduLines = sections.education.split("\n").map(l => l.trim()).filter(Boolean);
    const degrees  = eduLines.filter(l => degreeRe.test(l));
    education = degrees.length > 0
      ? degrees.join("; ")
      : eduLines.slice(0, 3).join("; ");
  }

  // ── 9. SUMMARY ────────────────────────────────────────
  const summary = sections.summary
    ? sections.summary.replace(/\n/g, " ").trim()
    : null;

  // ── 10. LANGUAGES ─────────────────────────────────────
  const KNOWN_LANGS = ["english","urdu","arabic","french","german","spanish","chinese","hindi","punjabi","turkish","persian","japanese","portuguese","russian","italian"];
  const langSrc = (sections.languages || text).toLowerCase();
  const languages = KNOWN_LANGS
    .filter(l => langSrc.includes(l))
    .map(l => l.charAt(0).toUpperCase() + l.slice(1));

  // ── 11. GENDER (resume mein hota kam hi hai) ──────────
  let gender = null;
  const genderMatch = text.match(/\b(male|female|m|f)\b/i);
  if (genderMatch) gender = genderMatch[0];

  // ── FINAL OUTPUT (Affinda-style format) ───────────────
  return {
    Name:                name            || "Not specified",
    Email:               email           || "Not specified",
    Phone:               phone           || "Not specified",
    Gender:              gender          || "Not specified",
    Skills:              skills          || "Not specified",
    City:                city            || "Not specified",
    State:               state           || "Not specified",
    Country:             country         || "Not specified",
    WorkHistory:         workHistory     || "Not specified",
    Locality:            "Not specified",
    FullAddress:         fullAddress     || "Not specified",
    PostalCode:          "Not specified",
    PositionTitle:       positionTitle   || "Not specified",
    CurrentOrganization: currentOrganization || "Not specified",
    TotalExperience:     totalExperience || "Not specified",
    Summary:             summary         || "Not specified",
    LinkedInUrl:         linkedInUrl     || "Not specified",
    Education:           education       || "Not specified",
    Languages:           languages.length > 0 ? languages.join(", ") : "Not specified",
  };
}

// ── Run & Return ──────────────────────────────────────────
const extracted = extractResumeData(text);

return { json: extracted };

// ════════════════════════════════════════════════════════
//  n8n Code Node — Resume Parser (Deep Extraction)
//  Fields: Name, Email, Phone, Gender, Skills, City, State,
//          Country, WorkHistory, Locality, FullAddress,
//          PostalCode, PositionTitle, CurrentOrganization,
//          TotalExperience, Summary, LinkedInUrl, Education
//  Input:  $input.item.json.text  (plain text of resume)
// ════════════════════════════════════════════════════════

const text = $input.item.json.text || "";
const lines = text.split("\n").map(l => l.trim()).filter(Boolean);

// ── UTILITY: first regex match ────────────────────────────
function match(pattern, src) {
  const m = (src || text).match(pattern);
  return m ? m[0].trim() : null;
}

// ════════════════════════════════════════════════════════
// SECTION SPLITTER
// ════════════════════════════════════════════════════════
function getSections(txt) {
  const HEADERS = {
    summary:        /^(summary|objective|professional\s*summary|career\s*objective|profile|about\s*me)$/i,
    skills:         /^(skills|technical\s*skills|key\s*skills|core\s*competencies|technologies|expertise)$/i,
    experience:     /^(experience|work\s*experience|professional\s*experience|employment(\s*history)?|work\s*history|career\s*history)$/i,
    education:      /^(education|academic(\s*background)?|qualifications?|educational\s*details?)$/i,
    certifications: /^(certifications?|licenses?|credentials?|courses?|training)$/i,
    projects:       /^(projects?|personal\s*projects?|key\s*projects?)$/i,
    languages:      /^(languages?|language\s*proficiency|spoken\s*languages?)$/i,
  };

  const secLines = txt.split("\n");
  const positions = [];

  secLines.forEach((line, idx) => {
    const clean = line.trim().replace(/:$/, "");
    if (!clean || clean.length > 60 || /@|\.com/.test(clean)) return;
    for (const [key, re] of Object.entries(HEADERS)) {
      if (re.test(clean)) {
        positions.push({ key, idx });
        break;
      }
    }
  });

  const result = {};
  positions.forEach(({ key, idx }, i) => {
    const end = i + 1 < positions.length ? positions[i + 1].idx : secLines.length;
    result[key] = secLines.slice(idx + 1, end).join("\n").trim();
  });
  return result;
}

const SEC = getSections(text);

// ════════════════════════════════════════════════════════
// 1. NAME
// ════════════════════════════════════════════════════════
let Name = null;
for (let i = 0; i < Math.min(6, lines.length); i++) {
  const l = lines[i];
  const words = l.split(/\s+/);
  if (
    words.length >= 2 && words.length <= 5 &&
    /^[A-Z]/.test(l) &&
    !/@|http|linkedin|github|\d/.test(l) &&
    words.every(w => /^[A-Za-z'\-\.]+$/.test(w))
  ) {
    Name = l;
    break;
  }
}

// ════════════════════════════════════════════════════════
// 2. EMAIL
// ════════════════════════════════════════════════════════
const Email = match(/[\w.\-+]+@[\w\-]+\.[a-zA-Z]{2,}/);

// ════════════════════════════════════════════════════════
// 3. PHONE
// ════════════════════════════════════════════════════════
const Phone = match(/(\+?[\d][\d\s\-().]{7,}[\d])/);

// ════════════════════════════════════════════════════════
// 4. GENDER
// ════════════════════════════════════════════════════════
let Gender = null;
const genderM = text.match(/\b(male|female|man|woman|m\/f|gender\s*:\s*\w+)\b/i);
if (genderM) {
  Gender = genderM[0].replace(/gender\s*:\s*/i, "").trim();
  Gender = Gender.charAt(0).toUpperCase() + Gender.slice(1).toLowerCase();
}

// ════════════════════════════════════════════════════════
// 5. SKILLS  → single comma-separated string
// ════════════════════════════════════════════════════════
let Skills = null;
if (SEC.skills) {
  const raw = SEC.skills.replace(/[•\-\*▪◦→]/g, ",");
  const arr = raw.split(/[,\n|\/]/)
    .map(s => s.trim())
    .filter(s => s.length > 1 && s.length < 80);
  Skills = [...new Set(arr)].join(", ");
}

// ════════════════════════════════════════════════════════
// 6. LOCATION → City, State, Country, FullAddress, PostalCode, Locality
// ════════════════════════════════════════════════════════
let City = null, State = null, Country = null;
let FullAddress = null, PostalCode = null, Locality = null;

// Postal code (PIN / ZIP)
const postalM = text.match(/\b\d{5,6}\b/);
if (postalM) PostalCode = postalM[0];

// City, State, Country — "Gandhinagar, Gujarat, India" style
const loc3 = text.match(
  /\b([A-Z][a-z]+(?:[\s\-][A-Z][a-z]+)?),\s*([A-Z][a-z]+(?:[\s\-][A-Z][a-z]+)?),\s*(India|Pakistan|USA|UK|Canada|Australia|Germany|UAE|Saudi Arabia|Qatar|Singapore|USA|United States|United Kingdom)\b/
);
const loc2 = text.match(
  /\b([A-Z][a-z]+(?:[\s\-][A-Z][a-z]+)?),\s*(India|Pakistan|USA|UK|Canada|Australia|Germany|UAE|Saudi Arabia|Qatar|Singapore|United States|United Kingdom)\b/
);

if (loc3) {
  City = loc3[1]; State = loc3[2]; Country = loc3[3];
  FullAddress = `${City}, ${State}, ${Country}`;
} else if (loc2) {
  City = loc2[1]; Country = loc2[2];
  FullAddress = `${City}, ${Country}`;
} else {
  // country alone
  const COUNTRIES = ["India","Pakistan","USA","UK","Canada","Australia","Germany","UAE","Saudi Arabia","Qatar","Singapore","United States","United Kingdom"];
  for (const c of COUNTRIES) {
    if (text.includes(c)) { Country = c; break; }
  }
}

// Locality — neighbourhood/area (optional, often not in resumes)
const localityM = text.match(/\b(locality|area|sector|nagar|colony|township)\s*[:\-]?\s*([A-Za-z\s]+)/i);
if (localityM) Locality = localityM[2].trim();

// ════════════════════════════════════════════════════════
// 7. WORK HISTORY — Smart Detection
//    Strategy 1: Section heading mil gaya → parse karo
//    Strategy 2: No heading → poore text se job patterns dhundo
//    Signals: job titles, "at"/"@" company, date ranges
// ════════════════════════════════════════════════════════
let WorkHistory = null;
let PositionTitle = null;
let CurrentOrganization = null;
let TotalExperience = null;

// ── Known job title keywords ──────────────────────────
const JOB_TITLE_RE = /\b(manager|engineer|developer|analyst|consultant|director|officer|executive|coordinator|specialist|associate|lead|head|intern|architect|designer|scientist|researcher|advisor|president|vp|ceo|cto|cfo|founder|partner|supervisor|administrator|assistant|representative|accountant|team\s*leader|project\s*manager|product\s*manager|business\s*analyst|data\s*analyst|software\s*engineer|sales\s*manager|hr\s*manager|marketing\s*manager|process\s*consultant|research\s*analyst|apac\s*representative|chief\s*coordinator|dy\.?\s*manager|dg\s*manager)\b/i;

// ── Date range pattern: Oct'22–Oct'25, 2018-2022, Jan 2020 - Present ──
const DATE_RANGE_RE = /((?:jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z']*[\s,]*\d{2,4}|(?:19|20)\d{2})\s*[-–to]+\s*((?:jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z']*[\s,]*\d{2,4}|(?:19|20)\d{2}|present|current|now|till\s*date|ongoing)/gi;

// ── "at" company extractor ────────────────────────────
const AT_COMPANY_RE = /\bat\s+([A-Z][A-Za-z0-9\s&,.\-']+(?:Pvt\.?\s*Ltd\.?|LLC|Inc\.?|Corp\.?|Limited|Services|Consulting|Solutions|Associates|Group|International|Technologies|University)?)/;

// ── STEP 1: Try section-based parsing first ───────────
function parseExpSection(expText) {
  const blocks = expText.split(/\n{2,}/);
  const entries = [];
  const allYears = [];

  blocks.forEach(block => {
    const bLines = block.split("\n").map(l => l.trim()).filter(Boolean);
    if (!bLines.length) return;

    const titleLine   = bLines[0] || "";
    const companyLine = bLines[1] || "";

    // dates in this block
    const dateMatches = [...block.matchAll(DATE_RANGE_RE)];
    let duration = "";
    if (dateMatches.length > 0) {
      const d = dateMatches[0];
      duration = `(${d[1]}-${d[2]})`;
    } else {
      const singleYear = block.match(/\b(19|20)\d{2}\b/);
      if (singleYear) duration = `(${singleYear[0]})`;
    }

    // collect years
    const yrs = block.match(/\b(19|20)\d{2}\b/g) || [];
    yrs.forEach(y => allYears.push(parseInt(y)));

    if (titleLine) {
      const entry = companyLine
        ? `${titleLine} at ${companyLine} ${duration}`.trim()
        : `${titleLine} ${duration}`.trim();
      entries.push({ title: titleLine, company: companyLine, duration, entry });
    }
  });

  return { entries, allYears };
}

// ── STEP 2: Smart full-text scan (no section heading) ─
function smartScanJobs(fullText) {
  const entries = [];
  const allYears = [];
  const textLines = fullText.split("\n").map(l => l.trim()).filter(Boolean);

  for (let i = 0; i < textLines.length; i++) {
    const line = textLines[i];

    // Is this line a job title?
    if (JOB_TITLE_RE.test(line) && line.length < 100) {

      let company = null;
      let duration = "";

      // Check same line for "at Company"
      const atMatch = line.match(AT_COMPANY_RE);
      if (atMatch) company = atMatch[1].trim();

      // Check nearby lines (next 3) for company + dates
      const nearby = textLines.slice(i, i + 4).join(" ");
      const dateMatches = [...nearby.matchAll(DATE_RANGE_RE)];
      if (dateMatches.length > 0) {
        const d = dateMatches[0];
        duration = `(${d[1]}-${d[2]})`;
        nearby.match(/\b(19|20)\d{2}\b/g)?.forEach(y => allYears.push(parseInt(y)));
      }

      // If company not found on same line, check next line
      if (!company && textLines[i + 1]) {
        const nextLine = textLines[i + 1];
        // Next line is company if: not a job title itself, not a date, starts with capital
        if (
          !JOB_TITLE_RE.test(nextLine) &&
          !/^(19|20)\d{2}/.test(nextLine) &&
          /^[A-Z]/.test(nextLine) &&
          nextLine.length < 100
        ) {
          company = nextLine;
        }
      }

      const entry = company
        ? `${line} at ${company} ${duration}`.trim()
        : `${line} ${duration}`.trim();

      // Avoid duplicates
      if (!entries.find(e => e.title === line)) {
        entries.push({ title: line, company, duration, entry });
      }
    }
  }

  return { entries, allYears };
}

// ── COMBINE: use section if found, else smart scan ────
let parsedEntries = [];
let parsedYears   = [];

if (SEC.experience) {
  const { entries, allYears } = parseExpSection(SEC.experience);
  parsedEntries = entries;
  parsedYears   = allYears;
}

// Agar section se kuch nahi mila → poore text scan karo
if (parsedEntries.length === 0) {
  const { entries, allYears } = smartScanJobs(text);
  parsedEntries = entries;
  parsedYears   = allYears;
}

// ── Build final fields ────────────────────────────────
if (parsedEntries.length > 0) {
  WorkHistory         = parsedEntries.map(e => e.entry).join(", ");
  PositionTitle       = parsedEntries[0].title       || null;
  CurrentOrganization = parsedEntries[0].company     || null;
}

// Total Experience calculation
if (parsedYears.length > 0) {
  const earliest = Math.min(...parsedYears);
  const now      = new Date().getFullYear();
  const diff     = now - earliest;
  if (diff > 0 && diff < 60) TotalExperience = `Over ${diff} Years`;
}

// Fallback: scan for duration phrases like "5 years experience"
if (!TotalExperience) {
  const expPhrase = text.match(/(\d+)\+?\s*years?\s*(of\s*)?(experience|exp)/i);
  if (expPhrase) TotalExperience = `Over ${expPhrase[1]} Years`;
}

// ════════════════════════════════════════════════════════
// 8. SUMMARY
// ════════════════════════════════════════════════════════
let Summary = null;
if (SEC.summary) {
  Summary = SEC.summary.replace(/\n/g, " ").trim();
}

// ════════════════════════════════════════════════════════
// 9. LINKEDIN URL
// ════════════════════════════════════════════════════════
let LinkedInUrl = null;
const liRaw = match(/linkedin\.com\/in\/[\w\-]+/i);
if (liRaw) LinkedInUrl = "https://" + liRaw;

// ════════════════════════════════════════════════════════
// 10. EDUCATION → full string like screenshot
// ════════════════════════════════════════════════════════
let Education = null;
if (SEC.education) {
  const degreeRe = /bachelor|master|b\.?s\.?|m\.?s\.?|phd|b\.?e|m\.?b\.?a|matric|intermediate|fsc|bsc|associate|diploma|certificate|mba|pgd|msc|bca|mca|b\.?tech|m\.?tech/i;
  const eduLines = SEC.education.split("\n").map(l => l.trim()).filter(Boolean);

  // group: degree line + institution line pairs
  const eduParts = [];
  for (let i = 0; i < eduLines.length; i++) {
    if (degreeRe.test(eduLines[i])) {
      const yearM = eduLines[i].match(/(19|20)\d{2}/);
      const inst  = (!degreeRe.test(eduLines[i+1] || "") && eduLines[i+1]) ? eduLines[i+1] : null;
      const year  = yearM ? yearM[0] : (eduLines[i+1]?.match(/(19|20)\d{2}/)?.[0] || null);
      let part    = eduLines[i];
      if (inst)  part += `, ${inst}`;
      if (year && !eduLines[i].includes(year)) part += `, ${year}`;
      eduParts.push(part);
      if (inst) i++; // skip institution line
    }
  }

  Education = eduParts.length > 0
    ? eduParts.join("; ")
    : eduLines.slice(0, 5).join("; ");
}

// ════════════════════════════════════════════════════════
// FINAL OUTPUT — exact field names from screenshot
// ════════════════════════════════════════════════════════
return {
  json: {
    Name:                Name                || "Not specified",
    Email:               Email               || "Not specified",
    Phone:               Phone               || "Not specified",
    Gender:              Gender              || "Not specified",
    Skills:              Skills              || "Not specified",
    City:                City                || "Not specified",
    State:               State               || "Not specified",
    Country:             Country             || "Not specified",
    WorkHistory:         WorkHistory         || "Not specified",
    Locality:            Locality            || "Not specified",
    FullAddress:         FullAddress         || "Not specified",
    PostalCode:          PostalCode          || "Not specified",
    PositionTitle:       PositionTitle       || "Not specified",
    CurrentOrganization: CurrentOrganization || "Not specified",
    TotalExperience:     TotalExperience     || "Not specified",
    Summary:             Summary             || "Not specified",
    LinkedInUrl:         LinkedInUrl         || "Not specified",
    Education:           Education           || "Not specified",
  }
};
